// §11.6.1 PLANOVAC NIBE->bazen pro bazen_na_max (case 3)
// Vybere nejlevnejsich N hodin v horizontu podle pocitu potrebnych cyklu.
// Nastavi flow.pool_nibe_planned_now = true pokud aktualni hodina je v top-N.
const cfg = global.get("fve_config") || {};
// CRITICAL GUARD (§11.1): pool flow NESMI pracovat mimo letni rezim.
// FIX (10.5.2026 21:19, BUG 4): pool_enabled LIVE z HA (ne cached cfg).
function _gBp(id, d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;return s.state==="on";}
const _letniLiveP = _gBp("input_boolean.letni_rezim", cfg.letni_rezim === true);
const _poolEnabledLiveP = _gBp("input_boolean.automatizovat_vytapeni_bazenu", cfg.pool_enabled === true);
if (!_letniLiveP || !_poolEnabledLiveP) {
    global.set("pool_nibe_planned_hours", []);
    flow.set("pool_nibe_planned_hours", []);
    flow.set("pool_nibe_planned_now", false);
    node.status({fill: "grey", shape: "ring", text: "off (letni/enabled)"});
    return msg;
}
const planData = global.get("fve_plan") || {};
const plan = Array.isArray(planData.plan) ? planData.plan : [];

function getFloat(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    const v = parseFloat(s.state);
    return isNaN(v) ? def : v;
}
function getBool(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    return s.state === "on";
}

const poolNaMax = getBool("input_boolean.bazen_na_max", false);
if (!poolNaMax || plan.length === 0) {
    flow.set("pool_nibe_planned_now", false);
    flow.set("pool_nibe_planned_hours", []);
    global.set("pool_nibe_planned_hours", []);
    node.status({fill: "grey", shape: "ring", text: "bazen_na_max=off"});
    return msg;
}

const vody = getFloat("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20);
const cil = getFloat("input_number.pozadovana_teplota_v_bazenu", 28);
const deltaT = Math.max(0, cil - vody);
const cyklyPerDeg = cfg.pool_cykly_per_degree || 2;
const cyklesNeeded = Math.ceil(deltaT * cyklyPerDeg);
if (cyklesNeeded === 0) {
    flow.set("pool_nibe_planned_now", false);
    flow.set("pool_nibe_planned_hours", []);
    global.set("pool_nibe_planned_hours", []);
    node.status({fill: "green", shape: "ring", text: "cil dosazen " + vody.toFixed(1) + "°"});
    return msg;
}

const horizon = Math.min(cfg.pool_nibe_plan_horizon_h || 24, plan.length);
const window = plan.slice(0, horizon);
const sorted = window
    .map((p, idx) => ({ idx, price: parseFloat(p.priceBuy) }))
    .filter(x => !isNaN(x.price))
    .sort((a, b) => a.price - b.price);
const topIdxs = sorted.slice(0, cyklesNeeded).map(x => x.idx);
const plannedNow = topIdxs.includes(0);
flow.set("pool_nibe_planned_hours", topIdxs);
flow.set("pool_nibe_planned_now", plannedNow);
global.set("pool_nibe_planned_hours", topIdxs);  // §11.9 fve_plan integrace (B4)

node.status({fill: plannedNow?"blue":"grey", shape: "ring",
    text: "cyklu=" + cyklesNeeded + " top=[" + topIdxs.slice(0,6).join(",") + "]" + (plannedNow?" NOW":"")});
return msg;

// §11.6 NIBE -> bazen use cases + 30 min runtime protection
// In:  msg (z planneru). Out: {action:"nibe_on"/"nibe_off"} nebo NULL (no-op).
// Flow: pool_nibe_running, pool_nibe_start_ts. Global: pool_heating_filtrace_lock_until.
const cfg = global.get("fve_config") || {};
function gF(id,d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;const v=parseFloat(s.state);return isNaN(v)?d:v;}
function gB(id,d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;return s.state==="on";}

// §11.6 ZAKLADNI POVOLENI: letni_rezim + pool_enabled + automatizovat_vytapeni_bazenu
// Pokud kterekoli OFF -> NIBE bazen NIKDY nebezi. Pokud uz bezel, dokonci min runtime, pak OFF.
// RECOVERY (9.5.2026 + 23.5.2026 fix): pokud nibeOn=true ale startTs=0 (NR restart),
// rekonstruuj startTs z switch.last_changed (perzistuje v HA pres restarty NR).
// PUVODNI BUG (23.5.2026): pri NR restart se startTs resetoval na Date.now() -> 30 min
// guard se pocital znovu od restartu -> NIBE zustaval ON i kdyz podminky chtely OFF.
// FIX (23.5.2026): BUG — pool_nibe_decide cetla cached cfg.letni_rezim/cfg.pool_enabled,
// fve-config state-listener ("HA Config zmena") neobsahoval pool entity, takze po user zmene
// bazen_na_max/automatizovat_vytapeni_bazenu se cfg nerebuildoval. Guard pak rejectoval start.
// LIVE read z HA — analogie BUG 4 fix z 10.5.2026 (patrony korekce, planner, guard_data).
const _letniLive = gB("input_boolean.letni_rezim", cfg.letni_rezim === true);
const _poolEnabledLive = gB("input_boolean.automatizovat_vytapeni_bazenu", cfg.pool_enabled === true);
const nibeOn = gB("switch.nibe_jednorazove_zvyseni_tuv", false);
if (nibeOn && !(flow.get("pool_nibe_start_ts")||0)) {
    const _sw = global.get("homeassistant.homeAssistant.states['switch.nibe_jednorazove_zvyseni_tuv']") || {};
    let _recoverTs = 0;
    if (_sw.last_changed) {
        const _t = Date.parse(_sw.last_changed);
        if (!isNaN(_t)) _recoverTs = _t;
    }
    flow.set("pool_nibe_start_ts", _recoverTs || Date.now());
    flow.set("pool_nibe_running", true);
}
if (!_letniLive || !_poolEnabledLive) {
    const _now = Date.now();
    const _startTs = flow.get("pool_nibe_start_ts") || 0;
    const _runSec = (nibeOn && _startTs) ? (_now - _startTs) / 1000 : 0;
    const _minRun = cfg.pool_nibe_min_runtime_sec || 1800;
    const _canStop = _runSec >= _minRun;
    const _why = !_letniLive ? "letni" : "pool_enabled";
    if (nibeOn && !_canStop) {
        flow.set("pool_nibe_running", true);
        global.set("pool_heating_filtrace_lock_until", _now + 70000 + (cfg.pool_filtrace_cooldown_min||10)*60000);
        node.status({fill:"red",shape:"dot",text:"OFF ("+_why+") dobeh "+Math.round(_minRun-_runSec)+"s"});
        return null;
    }
    if (nibeOn) {
        flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
        node.status({fill:"yellow",shape:"dot",text:"OFF ("+_why+") -> NIBE_OFF"});
        return {action: "nibe_off"};
    }
    flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
    node.status({fill: "grey", shape: "ring", text: "OFF ("+_why+")"});
    return null;
}

const vody = gF("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20);
const cil = gF("input_number.pozadovana_teplota_v_bazenu", 28);
const poolNaMax = gB("input_boolean.bazen_na_max", false);
const planData = global.get("fve_plan") || {};
const cur = (Array.isArray(planData.plan) && planData.plan.length) ? planData.plan[0] : {};
const buyPrice = parseFloat(cur.priceBuy);
// B7: fveMode source priority — global.fve_current_mode (NR live) ->
//   planData.current_mode (NR cache) -> sensor.fve_plan_data (HA persist) ->
//   sensor.fve_plan (HA persist starsi). Brani race po restartu NR.
const _fpd = (global.get("homeassistant.homeAssistant.states['sensor.fve_plan_data']") || {}).attributes || {};
const _fpa = (global.get("homeassistant.homeAssistant.states['sensor.fve_plan']") || {}).attributes || {};
const fveMode = global.get("fve_current_mode") || planData.current_mode || _fpd.current_mode || _fpa.current_mode || "";
const solarRemE = global.get("homeassistant.homeAssistant.states['sensor.energy_production_today_remaining_3']") || {};
const solarRem = parseFloat(solarRemE.state) || 0;

const now = Date.now();
const startTs = flow.get("pool_nibe_start_ts") || 0;
const runSec = (nibeOn && startTs) ? (now - startTs) / 1000 : 0;
const minRun = cfg.pool_nibe_min_runtime_sec || 1800;
const canStop = runSec >= minRun;

// 1) STROP VODY: povinny dobeh min_runtime, pak off
// B5: HYSTEREZE 0.3 °C — strop drzi flow.pool_nibe_strop_active=true,
// dokud vody neklesne pod cil-0.3. Brani oscilaci pri kolisani teplomeru.
const stropHyst = 0.3;
let stropActive = flow.get("pool_nibe_strop_active") === true;
if (vody >= cil) stropActive = true;
else if (vody < cil - stropHyst) stropActive = false;
flow.set("pool_nibe_strop_active", stropActive);
if (stropActive) {
    if (nibeOn && !canStop) {
        flow.set("pool_nibe_running", true);
        global.set("pool_heating_filtrace_lock_until", now + 70000 + (cfg.pool_filtrace_cooldown_min||10)*60000);
        node.status({fill:"red",shape:"dot",text:"CIL "+vody.toFixed(1)+"° dobeh "+Math.round(minRun-runSec)+"s"});
        return null;
    }
    if (nibeOn) {
        flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
        node.status({fill:"green",shape:"dot",text:"CIL "+vody.toFixed(1)+"° → OFF"});
        return {action: "nibe_off"};
    }
    flow.set("pool_nibe_running", false);
    node.status({fill:"green",shape:"ring",text:"CIL "+vody.toFixed(1)+"° (off, hyst<"+(cil-stropHyst).toFixed(1)+")"});
    return null;
}

// 2) USE CASES (§11.6) — zakladni povoleni resí guard nahore.
// FIX (23.5.2026, uzivatel): v bazen_na_max=ON novy chovani:
//   - ULTRA (buy <= prah_ultra_levna_nakup, default 1 Kc): NIBE jede I ZE SITE (vyjimka, OK)
//   - NORMAL (buy > 1 Kc): NIBE jede JEN pokud solar staci pokrytí (NEZRAT ZE SITE)
//   - SOC baterie ignorovan (user kasle na SOC, chce maximalni topeni bazenu)
// Plánovač (c2 pred fixem) zrusen jako trigger — mohl vybrat drahou non-solar nocni hodinu.
// Plánovač zustava jen pro UI display (isPoolNibeHour v sensor.fve_plan).
// 8.5.2026: zruseno samostatne "zakaz pretoku + solar >=13" — zakaz pretoku sam o sobe
//   nikdy nespousti NIBE, ale je soucasti "dostatecny solar" testu (sell <= 0 -> vzdy ok).
// FIX (23.5.2026 v2, uzivatel): NIBE jede VYHRADNE pri zaporne nebo ULTRA cene (≤ 1 Kc).
// V non-ultra hodinach (buy > 1 Kc) NIBE NIKDY nejede — i kdyby solar byl velky.
// Misto NIBE jedou PATRONY (skalovatelne 3/6/9 kW per §8.5) v pool_decide_logic
// s bypass SOC/solar pri bazen_na_max + cantExport (§11.7 vyjimka 23.5.2026).
// Patrony pomalu plni nadrz, NIBE drzi OFF dokud nezacne ultra hodina.
// Duvod: NIBE je 3.5 kW fix — pri drahych hodinach uz mame draho zaplaceno za vse co
// neprijde do baterie, lepsi je pomalu skalovat patronama nez riskovat ze NIBE pojede
// par minut a pak stop pri zmene spotreby auta/domu.
const c1 = !isNaN(buyPrice) && buyPrice <= (cfg.pool_nibe_zaporna_cena_threshold ?? 0);
const isUltra = !isNaN(buyPrice) && buyPrice <= (cfg.prah_ultra_levna_nakup || 1.0);
const c2_ultra = poolNaMax && isUltra;
// §4.10.2 (user 17.6.2026): NIBE->bazen = DUMP LOAD POSLEDNI PRIORITY pri zaporne/nulove cene.
// Nejdriv se nasiti skalovatelne spotrebice (auto/patrony/bojler/filtrace) + baterie (buffer).
// NIBE (12 kW, neskalovatelne) se ZAPNE az kdyz uz neni co krmit: grid odber klesl pod floor
// A baterie se uz nedobiji (plna/limitovana) => bez NIBE bychom nedrzeli cilovy ~18 kW odber.
// BEH se drzi dokud buy<=0 (anyKeep) — strop vody / min_runtime resi konec, zadny short-cycle.
const _isZapMode = fveMode === "zaporna_nakupni_cena";
const _gridFloor = cfg.zaporna_nibe_grid_floor_w || 15000;
const _chgFloor = cfg.zaporna_nibe_bat_charge_floor_w || 800;
let _gridNow = parseFloat((global.get("homeassistant.homeAssistant.states['sensor.spotreba_ze_site']") || {}).state); if (isNaN(_gridNow)) _gridNow = 0;
let _batChgNow = parseFloat((global.get("homeassistant.homeAssistant.states['sensor.nabijeni_baterii_plus']") || {}).state); if (isNaN(_batChgNow) || _batChgNow < 0) _batChgNow = 0;
const _nibeLastResort = (!_isZapMode) || (_gridNow < _gridFloor && _batChgNow < _chgFloor);
const anyStart = (c1 && _nibeLastResort) || c2_ultra;
const anyKeep = c1 || c2_ultra;
// tag priorita: zap > ultra (pro status text)
const tag = c1 ? "zap" : c2_ultra ? "ultra" : "-";

let action = null; let reason = "";
if (!nibeOn && anyStart) {
    flow.set("pool_nibe_start_ts", now); flow.set("pool_nibe_running", true);
    action = "nibe_on"; reason = "→ON "+tag+(isNaN(buyPrice)?"":" "+buyPrice.toFixed(2)+"Kc");
} else if (nibeOn && !anyKeep) {
    // FIX (23.5.2026 v3): bypass min_runtime guard pro "no-case" branch.
    // Pokud zadny case neplati (NIBE NEMA bezet per § 11.6 v3), OKAMZITY STOP
    // bez cekani 30 min. Duvod: kratky cyklus kompresoru < ZRANI ZE SITE.
    // Min runtime guard zustava aktivni JEN ve "strop vody" branch (legitimni
    // konec po dosazeni cilove teploty bazenu).
    flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
    action = "nibe_off";
    reason = canStop ? "→OFF no-case "+Math.round(runSec/60)+"m"
                     : "→OFF no-case BYPASS min_runtime ("+Math.round(runSec/60)+"m)";
} else if (nibeOn && anyKeep) {
    flow.set("pool_nibe_running", true);
    reason = "run "+Math.round(runSec/60)+"m "+tag;
} else {
    // FIX (7.6.2026): stale-flag — spinac NIBE->bazen je OFF a zadny case neplati.
    // Driv tato vetev neresetovala pool_nibe_running -> flag visel true -> topeni_mod
    // "BAZEN - NIBE" + forceAll patron (SOC>=95 + zakaz pretoku) zablokovan pres
    // !_nibeBazenRunning. Realny stav NIBE = klidovy => flag MUSI byt false.
    flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
    reason = "idle (off, no-case)";
}
// FIX (23.5.2026): lock prodlouzeni jen behem behu NIBE (nibeOn && action != "nibe_off").
// Pri action="nibe_off" lock zustava jen na presnych cooldown_min minut (§11.4 = 10 min),
// bez +70s buffer (ten je urcen pro safety mezi 60s ticky behem behu).
// Pri action="nibe_on" set lock na cooldown_min — dalsi tick za 60s ho prodlouzi.
const _coolMs = (cfg.pool_filtrace_cooldown_min||10)*60000;
if (action === "nibe_off") {
    global.set("pool_heating_filtrace_lock_until", now + _coolMs);
} else if (action === "nibe_on") {
    global.set("pool_heating_filtrace_lock_until", now + _coolMs);
} else if (nibeOn) {
    global.set("pool_heating_filtrace_lock_until", now + 70000 + _coolMs);
}
const fill = (action==="nibe_on")?"blue":(action==="nibe_off")?"yellow":(nibeOn?"blue":"grey");
const shape = (nibeOn||action==="nibe_on")?"dot":"ring";
node.status({fill,shape,text:(action?action.toUpperCase()+" | ":"")+reason+" v="+vody.toFixed(1)+"° cil="+cil.toFixed(1)});
// FIX (23.5.2026): pri NIBE OFF action poslat re-eval trigger do filtrace flow po
// presnych cooldown_min min (10 min) — garantuje, ze filtrace se vypne ihned po expiry
// locku, bez cekani na dalsi 2-min tick filtrace (§11.4 + §10.1).
const _reCheck = action === "nibe_off" ? {payload: "recheck_after_nibe_off", delay: _coolMs + 5000} : null;
return [action ? {action} : null, _reCheck];

// POOL Heating — data collect trigger (60s).
// V B2 vsechno ctene v decision func z global.get (homeassistant state).
// Tento node zatim jen trigger propaguje. V pripadnych optimalizacich (B3)
// by sem slo pridat pre-fetch a aggregaci.
msg.payload = {ts: Date.now()};
return msg;

// POOL Heating — guard + cteni stavu + stropy (§11.3)
// Vystup: msg { cfg, data, stropReason } -> pool_decide_logic.
// Pokud guard zablokuje (zimni rezim / pool_enabled=off), vrati null (flow konci).

const cfg = global.get("fve_config") || {};

// Guard: letni_rezim + pool_enabled — VZDY LIVE z HA (ne cached cfg).
// FIX (10.5.2026 21:19, BUG 4): cfg se buduje s lagem, user vypnutim auta
// dostal patrony do stavu 'pool_enabled=cached_true' a pool flow stale ridil.
// Live HA read => zmena se projevi okamzite v dalsim 60s ticku.
function _gB(id, d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;return s.state==="on";}
const letniRezim = _gB("input_boolean.letni_rezim", cfg.letni_rezim === true);
const poolEnabled = _gB("input_boolean.automatizovat_vytapeni_bazenu", cfg.pool_enabled === true);
if (!letniRezim || !poolEnabled) {
    flow.set("pool_patrony_allowed", false);
    flow.set("pool_patrony_max_floor", 0);
    node.status({fill: "grey", shape: "ring",
        text: "OFF (letni=" + (letniRezim?"1":"0") + " enabled=" + (poolEnabled?"1":"0") + ")"});
    return null;
}

// Helpery
function getFloat(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    const v = parseFloat(s.state);
    return isNaN(v) ? def : v;
}
function getBool(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    return s.state === "on";
}
function isAvail(id) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    return !!s && s.state !== "unavailable" && s.state !== "unknown";
}

// Stavove veliciny
const data = {
    teplotaVody:   getFloat("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20),
    teplotaNadrz:  getFloat("sensor.teplota_smesovac_teplota", 20),
    solarW:        getFloat("sensor.vyroba_fve", 0),
    soc:           getFloat("sensor.battery_percent", 0),
    bCh:           getFloat("sensor.battery_dc_current", 0),
    autoMaHlad:    getBool("input_boolean.auto_ma_hlad", false),
    filtraceAvail: isAvail("switch.filtrace"),
    p1on:          getBool("switch.patrona_faze_1", false),
    p2on:          getBool("switch.patrona_faze_3_2", false),
    p3on:          getBool("switch.patrona_faze_3", false),
    ventilOn:      getBool("switch.bazen_ventil_smesovac", false),
    bojlerPower:   (function(){
        const c = global.get("homeassistant.homeAssistant.states['climate.smart_socket_thermostat_24090276694597600801c4e7ae0a2e53']");
        return (c && c.attributes && c.attributes.hvac_action === "heating") ? 2000 : 0;
    })(),  // §11.5 bod 6: konstanta 2 kW kdyz bojler topi (HA nema wattmetr)
};
// Prodejní cena (sell) + flag zákazu přetoků pro sell-price guard patron (§8.5 / §11.7)
data.sellPrice = getFloat("input_number.aktualni_cena_prodej_kwh_h", 0);
const fvePlanAttr = (global.get("homeassistant.homeAssistant.states['sensor.fve_plan']") || {}).attributes || {};
data.cantExport = (data.sellPrice <= 0) || (fvePlanAttr.current_mode === "zakaz_pretoku");

// B2: All-in flagy (§11.6 + §11.7) — bypass standardnich gate (solar/sell/SOC)
// pri zaporne cene, zakazu pretoku, nebo bazen_na_max + ultra-levne cene.
// Buy price entita: input_number.aktualni_cena_kwh (Kc/kWh)
const buyPrice = getFloat("input_number.aktualni_cena_kwh", 99);
data.zapornaCena = buyPrice <= (cfg.pool_nibe_zaporna_cena_threshold != null ? cfg.pool_nibe_zaporna_cena_threshold : 0);
data.ultraLevna  = buyPrice <= (cfg.prah_ultra_levna_nakup || 1);
data.poolNaMax   = getBool("input_boolean.bazen_na_max", cfg.pool_na_max === true);

data.activeFaze = (data.p1on?1:0) + (data.p2on?1:0) + (data.p3on?1:0);

// Stropy (§11.3) — user-changeable HA entity LIVE (BUG 2 fix 10.5.2026 21:19).
// fve_config se buduje s lagem; user zmena prahu by se reflektovala az pri dalsim refresh.
// Live read => zmena okamzite v dalsim 60s ticku.
data.cilTeplotaVody = getFloat("input_number.pozadovana_teplota_v_bazenu", cfg.pool_cilova_teplota_vody || 28);
data.maxTeplotaNadrz = getFloat("input_number.max_teplota_nadrz_bazen", cfg.pool_max_teplota_nadrz || 60);
data.minTeplotaNadrz = getFloat("input_number.min_teplota_nadrz_bazen", cfg.pool_min_teplota_nadrz || 30);
let stropReason = null;
if (data.teplotaVody >= data.cilTeplotaVody) {
    stropReason = "voda";  // cil -> patrony OFF + cooldown filtrace
} else if (data.teplotaNadrz >= data.maxTeplotaNadrz) {
    stropReason = "nadrz"; // strop nadrze -> patrony OFF (NIBE neresi)
}

msg.cfg = cfg;
msg.data = data;
msg.stropReason = stropReason;
return msg;

// POOL Heating — rozhodovaci logika (§11.3/§11.5/§11.7)
// Vstup:  msg { cfg, data, stropReason }
// Vystup: msg.decision = { patronyAllowed, patronyMaxFloor, ventilAction,
//                          lockUntil, mod, statusText, statusFill }

const cfg = msg.cfg;
const data = msg.data;
const now = Date.now();
const filtraceCoolMin = cfg.pool_filtrace_cooldown_min || 10;

const dec = {
    patronyAllowed: false,
    patronyMaxFloor: 0,
    ventilAction: null,      // "on" / "off" / null
    lockUntil: null,         // ms
    mod: "Vypnuto",
    statusText: "",
    statusFill: "grey",
};

// STROP VODY -> patrony OFF + cooldown filtrace
if (msg.stropReason === "voda") {
    dec.ventilAction = data.ventilOn ? "off" : null;
    dec.lockUntil = now + filtraceCoolMin * 60000;
    dec.mod = "Vypnuto";
    dec.statusFill = "green";
