// PATRONY PODMINKY (§11.5 + §11.7)
const auto    = !data.autoMaHlad;
const socOk   = data.soc >= (cfg.topeni_min_soc_patron || 90);
const solarOk = data.solarW >= (cfg.topeni_patron_min_solar_w || 5000);
// §8.5/§11.7: sell-price guard — pri vysoke prodejni cene patrony NESMI bezet
