const _poolEnabledLive = _gBl("input_boolean.automatizovat_vytapeni_bazenu", cfg.pool_enabled === true);
if (!_letniLive || !_poolEnabledLive) {
    node.status({fill: "grey", shape: "ring", text: "pool off (letni/enabled) — NESAHAT"});
    return null;
}
const allowed = flow.get("pool_patrony_allowed") === true;
const maxFloor = flow.get("pool_patrony_max_floor") || 0;

function getFloat(id, def) {
