}

target = Math.max(0, Math.min(target, maxFloorEff));
const acts = buildActions(target);
if (target !== actFaze) flow.set("pool_pat_last_change", Date.now());

node.status({
    fill: target > 0 ? "green" : "grey",
    shape: "dot",
    text: "korekce " + actFaze + "->" + target + "f | " + reason + " | maxF=" + maxFloorEff + (nibeRunning ? " (NIBE cap1)" : ""),
});

if (acts.length === 0) return null;
return {payload: acts};
